const KOCOTOM = [{"id":"4mSQXGi0zSk","dur":3852,"title":"SZZ: Paralelní algoritmy nad seznamy a stromy"},{"id":"xLnQet8cIVA","dur":3449,"title":"SZZ: Model PRAM, suma prefixů"},{"id":"2_U-A9tZhb4","dur":2557,"title":"SZZ: Regresní analýza"},{"id":"luqobVkniB4","dur":3997,"title":"SZZ: Časová a prostorová složitost"},{"id":"Iz9RFd5ENIU","dur":5214,"title":"SZZ: Nerozhodnutelnost"},{"id":"NxhjsWteUSU","dur":3894,"title":"SZZ: Prolog - Změna programu za běhu"},{"id":"Pp6tEZLkASI","dur":5389,"title":"SZZ: Prolog - Unifikace a vyhodnocování"},{"id":"fCOSrHTsslU","dur":6865,"title":"FLP: Příprava k půlsemestrální zkoušce"},{"id":"Eo6FVosifWk","dur":7142,"title":"SZZ: Lambda kalkul - definice pravdivostních hodnot a přirozených čísel"},{"id":"ELvZpu3NDF8","dur":3760,"title":"SZZ: Haskell - typy v jazyce a líné vyhodnocování"},{"id":"8rZUeI1zDZg","dur":7866,"title":"SZZ: Deterministická syntaktická analýza zdola nahoru"},{"id":"I-MZNKgZsHQ","dur":7071,"title":"SZZ: Deterministická syntaktická analýza shora dolů"},{"id":"sEOW2PDEv5Y","dur":4043,"title":"SZZ: Teorie aukcí"},{"id":"8n4xFgYmMd8","dur":20433,"title":"Formální jazyky a překladače: Proudění k přípravě na zkoušku"},{"id":"JIuKYWaC7RA","dur":4521,"title":"SZZ: Převodníky a překladové gramatiky"},{"id":"SE9icZo1hgo","dur":4349,"title":"SZZ: Teorie veřejné volby"},{"id":"bpT5AV6j9N0","dur":20661,"title":"Teoretická informatika: Turingovy stroje"},{"id":"Vp_oBaNiIFg","dur":20409,"title":"Teoretická informatika: Bezkontextové jazyky"},{"id":"g8md4gN8PK0","dur":15265,"title":"Teoretická informatika - Regulární jazyky I"},{"id":"cPeqgx8sx4Y","dur":8379,"title":"SZZ: Vícevýběrové testy, testy o rozdělení"},{"id":"uQF-vwjvVyY","dur":16715,"title":"Teoretická informatika: Regulární jazyky II"},{"id":"5dxN6kG7wz4","dur":5879,"title":"SZZ: Konečné automaty"},{"id":"MRJrzmimB0w","dur":5148,"title":"SZZ: Zásobníkové automaty"},{"id":"jEUhyGfDGmo","dur":10447,"title":"SZZ: Bodové a intervalové odhady, statistické testy"},{"id":"zhuOFLxyJdw","dur":3544,"title":"SZZ: Randomizované algoritmy"},{"id":"XP3qg7Qv2So","dur":5949,"title":"SZZ: Markovské řetězce a jejich analýza"},{"id":"4LJzq6Bx64U","dur":7098,"title":"SZZ: Hledání nejkratších cest ze všech uzlů do všech ostatních uzlů grafu"},{"id":"WoYOsIXefJQ","dur":4254,"title":"SZZ: Maximální toky v sítích"},{"id":"e_bfl_FSirE","dur":5128,"title":"SZZ: Hledání nejkratších cest z jednoho uzlu do všech ostatních uzlů grafu"},{"id":"10WZZ3PHiO8","dur":4295,"title":"SZZ: Hledání minimální kostry grafu"},{"id":"8Z_sosW2dgU","dur":4575,"title":"SZZ : Lambda kalkul - úvod"},{"id":"VMQghxb5aSk","dur":5774,"title":"SZZ: Prohledávání grafů do hloubky a jeho aplikace"},{"id":"i9xUB0qRs2U","dur":4528,"title":"SZZ: Grafy a jejich prohledávání do šířky"},{"id":"KgY0rQZghTg","dur":6896,"title":"SZZ: Náhodné veličiny, významná rozdělení pravděpodobnosti"},{"id":"Vg8w9YMAqZU","dur":3586,"title":"SZZ: Pravděpodobnost"},{"id":"m-uP64Cq9Kc","dur":7744,"title":"SZZ: Chomského hierarchie a vlastnosti jazyků"},{"id":"YGEvSiS9ppg","dur":2661,"title":"SZZ: Regulární množiny, regulární výrazy"},{"id":"cjJXMGlk7xE","dur":5280,"title":"SZZ: Turingovy stroje a vyčíslitelné funkce"},{"id":"ZHWtCX3XMJk","dur":4912,"title":"SZZ: Základy diskrétní matematiky"},{"id":"bbkxv9QlJxQ","dur":3815,"title":"SZZ: Algebry s jednou a se dvěma operacemi"},{"id":"lz4UNeNWM-Q","dur":15978,"title":"Teoretická informatika: Složitost"},{"id":"amrvv9Lgrww","dur":20500,"title":"Teoretická informatika: Nerozhodnutelnost"}];
const KOCO_COURSES = ["TIN","FLP","PRL","MSP","SUI","AVS","UPA"];
const ALLOWLIST = ["Computerphile","Numberphile","3Blue1Brown","Reducible","Spanning Tree","Art of the Problem","Khan Academy","MIT OpenCourseWare","Stanford Online","CS50","CrashCourse","Veritasium","Welch Labs","Two Minute Papers","Sebastian Lague","Branch Education","Mathologer","Steve Brunton","mathematicalmonk","ritvikmath","StatQuest with Josh Starmer","Serrano.Academy","Visually Explained","Ben Eater","EEVblog","Asianometry","Core Dumped","Low Level","Low Level Learning","Jacob Sorber","Robert Feranec","Phil's Lab","Hussein Nasser","Gaurav Sen","ByteByteGo","PowerCert Animated Videos","Practical Networking","NetworkChuck","IBM Technology","Google for Developers","ArjanCodes","CodeAesthetic","Continuous Delivery","Fireship","The Net Ninja","Web Dev Simplified","Traversy Media","Academind","Kevin Powell","LiveOverflow","John Hammond","IppSec","PwnFunction","Cyrill Gössi","Andrej Karpathy","Yannic Kilcher","sentdex","DeepLearningAI","NNgroup","Nielsen Norman Group","AJ&Smart","Android Developers","Apple Developer","Philipp Lackner","CodeWithChris","freeCodeCamp.org","CMU Database Group","Hnasr","Spanning Tree","Tom Scott","Lex Fridman","PBS Infinite Series","Eli the Computer Guy","Hardware Unboxed","Gary Explains","Computer Science Lessons","Neso Academy","Abdul Bari","WilliamFiset","Back To Back SWE","Errichto","Tushar Roy - Coding Made Simple","mCoding","Tsoding","The Coding Train","Socratica","Derek Banas","Bisqwit"];

const KOCO_SCHEMA = {
  type: 'object', additionalProperties: false,
  properties: {
    course: { type: 'string' },
    maps: { type: 'array', items: {
      type: 'object', additionalProperties: false,
      properties: { topic: { type: 'string' }, sub: { type: 'string' }, videoId: { type: 'string' }, why: { type: 'string' } },
      required: ['topic', 'sub', 'videoId', 'why'],
    } },
  },
  required: ['course', 'maps'],
};
const REL_SCHEMA = {
  type: 'object', additionalProperties: false,
  properties: {
    course: { type: 'string' },
    picks: { type: 'array', items: {
      type: 'object', additionalProperties: false,
      properties: {
        topic: { type: 'string' }, sub: { type: 'string' },
        query: { type: 'string' }, channel: { type: 'string' },
        keywords: { type: 'array', items: { type: 'string' } }, why: { type: 'string' },
      },
      required: ['topic', 'sub', 'query', 'channel', 'keywords', 'why'],
    } },
  },
  required: ['course', 'picks'],
};

function subsList(c) {
  return c.topics.flatMap(t => t.subs.map(s => t.id + '/' + s.id + ' :: ' + s.title + '  (téma: ' + t.title + ')')).join('\n');
}

phase('Kocotom map');
const kocoList = KOCOTOM.map(v => v.id + '  [' + v.dur + 's]  ' + v.title).join('\n');
const kocoResults = await parallel(KOCO_COURSES.map(cid => () => {
  const c = COURSES[cid];
  if (!c) return null;
  const prompt = [
    "You map existing Czech YouTube lectures by 'Tomáš Kocourek' (channel @kocotom) onto subtopics of ONE university course in a Czech CS exam-prep app.",
    '',
    'COURSE: ' + cid + ' — ' + c.name,
    '',
    'SUBTOPICS (format  topicId/subId :: subtitle  (téma: topicTitle)):',
    subsList(c),
    '',
    'AVAILABLE VIDEOS (format  VIDEOID  [durationSeconds]  Title) — real fixed ids, copy verbatim:',
    kocoList,
    '',
    'TASK: For each video genuinely relevant to one or more subtopics of THIS course, output a mapping {topic, sub, videoId, why}.',
    '- These are long comprehensive lecture recordings; attach a video to the single best-matching subtopic, or a few if it squarely covers them.',
    '- One entry per (subtopic, video). A video may map to multiple subtopics across topics.',
    '- ONLY use videoId values copied EXACTLY from the AVAILABLE VIDEOS list. Never invent or alter an id.',
    '- topic and sub must be EXACT ids from the SUBTOPICS list (the part before/after the slash).',
    "- Be precise: a wrong topical match is worse than no match. If nothing fits, return an empty maps array.",
    "- 'why' = one short Czech clause.",
    'Return {course, maps}.',
  ].join('\n');
  return agent(prompt, { label: 'koco:' + cid, phase: 'Kocotom map', schema: KOCO_SCHEMA });
}));

phase('Reliable search');
const relResults = await parallel(Object.keys(COURSES).map(cid => () => {
  const c = COURSES[cid];
  const prompt = [
    'You are a CS educator curating ONE excellent YouTube explainer video per worthy subtopic of a university course, for a Czech exam-prep app. Videos are fetched LATER by an automated yt-dlp search using YOUR query — so your job is to (a) choose which subtopics deserve a video and (b) write a precise search query and name the channel.',
    '',
    'COURSE: ' + cid + ' — ' + c.name,
    '',
    'SUBTOPICS (topicId/subId :: subtitle (téma: topicTitle)):',
    subsList(c),
    '',
    'REPUTABLE CHANNELS — the resolver ONLY accepts a video whose channel matches the one you name here, and that channel MUST be one of these (or an obvious variant):',
    ALLOWLIST.join(', '),
    '',
    'TASK: For each subtopic where a well-known high-quality video from a reputable channel almost certainly exists, output a pick:',
    '- query: a YouTube search query likely to surface that exact video. INCLUDE the channel name, e.g. "Computerphile RSA encryption", "3Blue1Brown gradient descent", "Ben Eater error detection".',
    '- channel: the exact channel name (from the list above).',
    '- keywords: 2-5 lowercase words that MUST appear in the correct video title (used to score search hits).',
    "- why: one short clause on relevance.",
    'RULES:',
    '- QUALITY OVER COVERAGE. Skip any subtopic without a clearly-existing great video. Many/most subtopics will have none — that is expected; do NOT force generic videos.',
    '- One pick per subtopic at most (the single best video).',
    '- Prefer concept-explainer channels (Computerphile, 3Blue1Brown, Ben Eater, Reducible, StatQuest, Hussein Nasser, ByteByteGo, NNgroup, Fireship, etc.). Match the channel to the domain.',
    '- The topic must be squarely in scope; never attach an off-topic but famous video.',
    'Return {course, picks}.',
  ].join('\n');
  return agent(prompt, { label: 'rel:' + cid, phase: 'Reliable search', schema: REL_SCHEMA });
}));

return { koco: kocoResults.filter(Boolean), rel: relResults.filter(Boolean) };
